// ============ InMemoryTokenProvider.kt ============
package com.example.networking

class InMemoryTokenProvider : TokenProvider {
    private var accessToken: String? = null
    private var refreshTokenValue: String? = null

    fun setTokens(access: String, refresh: String? = null) {
        this.accessToken = access
        this.refreshTokenValue = refresh
    }

    override fun getAccessToken(): String? = accessToken

    override fun refreshToken(): String? = refreshTokenValue

    override fun clearTokens() {
        accessToken = null
        refreshTokenValue = null
    }
}

// ============ AuthInterceptor.kt ============
package com.example.networking

import okhttp3.Interceptor
import okhttp3.Response

class AuthInterceptor(private val tokenProvider: TokenProvider) : Interceptor {
    override fun intercept(chain: Interceptor.Chain): Response {
        val originalRequest = chain.request()

        val token = tokenProvider.getAccessToken()
        if (token.isNullOrEmpty()) {
            return chain.proceed(originalRequest)
        }

        val authenticatedRequest = originalRequest.newBuilder()
            .header("Authorization", "Bearer $token")
            .header("Accept", "application/json")
            .build()

        return chain.proceed(authenticatedRequest)
    }
}

// ============ TokenAuthenticator.kt ============
package com.example.networking

import okhttp3.Authenticator
import okhttp3.Request
import okhttp3.Response
import okhttp3.Route

class TokenAuthenticator(private val tokenProvider: TokenProvider) : Authenticator {
    override fun authenticate(route: Route?, response: Response): Request? {
        // Avoid infinite retry loops
        if (responseCount(response) >= 2) {
            tokenProvider.clearTokens()
            return null
        }

        val newToken = tokenProvider.refreshToken()
        if (newToken.isNullOrEmpty()) {
            tokenProvider.clearTokens()
            return null
        }

        return response.request.newBuilder()
            .header("Authorization", "Bearer $newToken")
            .build()
    }

    private fun responseCount(response: Response): Int {
        var count = 1
        var priorResponse = response.priorResponse
        while (priorResponse != null) {
            count++
            priorResponse = priorResponse.priorResponse
        }
        return count
    }
}

