// ============ Usage Example - ViewModel ============
package com.example.networking

import androidx.lifecycle.ViewModel
import androidx.lifecycle.viewModelScope
import com.example.networking.models.UserProfile
import com.example.networking.repository.UserRepository
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.StateFlow
import kotlinx.coroutines.launch

class UserViewModel(
    private val userRepository: UserRepository = UserRepository()
) : ViewModel() {

    private val _users = MutableStateFlow<List<UserProfile>>(emptyList())
    val users: StateFlow<List<UserProfile>> = _users

    private val _loading = MutableStateFlow(false)
    val loading: StateFlow<Boolean> = _loading

    private val _error = MutableStateFlow<String?>(null)
    val error: StateFlow<String?> = _error

    fun fetchUsers(page: Int = 1) {
        viewModelScope.launch {
            _loading.value = true
            _error.value = null

            when (val result = userRepository.getUsers(page)) {
                is NetworkResult.Success -> {
                    _users.value = result.data.data
                }
                is NetworkResult.Error -> {
                    _error.value = "Error ${result.code}: ${result.message}"
                }
                is NetworkResult.Exception -> {
                    _error.value = result.throwable.localizedMessage ?: "Unknown error"
                }
            }

            _loading.value = false
        }
    }

    fun fetchUserById(userId: Long) {
        viewModelScope.launch {
            _loading.value = true
            _error.value = null

            when (val result = userRepository.getUserById(userId)) {
                is NetworkResult.Success -> {
                    result.data.data?.let { user ->
                        _users.value = listOf(user)
                    }
                }
                is NetworkResult.Error -> {
                    _error.value = "Error ${result.code}: ${result.message}"
                }
                is NetworkResult.Exception -> {
                    _error.value = result.throwable.localizedMessage ?: "Unknown error"
                }
            }

            _loading.value = false
        }
    }
}